function imgui.CreateTextureFromFileInMemory(str)
	local stb = require("stb_image")
	local strcast = ffi.cast("void*", str)
	local image_width = ffi.new("int[1]")
	local image_height = ffi.new("int[1]")
	local channels_in_file = ffi.new("int[1]")
	local image_data = stb.stbi_load_from_memory(strcast, #str, image_width, image_height, channels_in_file, 0)
	local glformat = channels_in_file[0] == 4 and glc.GL_RGBA or glc.GL_RGB

	local image_texture = ffi.new("GLuint[1]")
	gl.glGenTextures(1, image_texture);
	gl.glBindTexture(glc.GL_TEXTURE_2D, image_texture[0]);

	gl.glTexParameteri(glc.GL_TEXTURE_2D, glc.GL_TEXTURE_MIN_FILTER, glc.GL_NEAREST)
	gl.glTexParameteri(glc.GL_TEXTURE_2D, glc.GL_TEXTURE_MAG_FILTER, glc.GL_NEAREST)

	gl.glTexImage2D(glc.GL_TEXTURE_2D, 0, glformat, image_width[0], image_height[0], 0, glformat, glc.GL_UNSIGNED_BYTE, image_data);
	return ffi.cast("void*", image_texture[0])
end

