local function GetModuleBase(pid, module_name)
    local snapshot = 0
    local me32 = ffi.new("MODULEENTRY32")
    me32.dwSize = ffi.sizeof("MODULEENTRY32")

    snapshot = ffi.C.CreateToolhelp32Snapshot(0x18, pid)

    if snapshot == ffi.cast("uint32_t", -1) then
        local err = ffi.C.GetLastError()
        print(string.format("[-] CreateToolhelp32Snapshot failed with code 0x%X!", err))
        return nil
    end

    ffi.C.Module32First(snapshot, me32)

    local found = false

    repeat
        if ffi.string(ffi.cast("char*", ffi.cast("uintptr_t", me32.szModule)+0x8)) == module_name then
            found = true
            break
        end
    until not ffi.C.Module32Next(snapshot, me32)

    if not found then
        return nil
    end

    local module_base = ffi.cast("uintptr_t", me32.modBaseAddr)

    ffi.C.CloseHandle(snapshot)

    return module_base
end

function AOBScanOpt(bytes, start, length) -- Optimized AoBScan by Corenale
	local finish = start + length - #bytes
    local putty = ffi.new("char[8]", bytes)

    local plastic = (#bytes > 7 and "uint64_t*") or (#bytes > 3 and "uint32_t*") or (#bytes > 1 and "uint16_t*") or "uint8_t*"
    local plasticKey = ffi.cast(plastic, putty)[0]
    
	for i = 0, length do
		local i = start + i
		if ffi.cast(plastic, i)[0] == plasticKey then
			if ffi.string(ffi.cast("void*", i), #bytes) == bytes then return i end
		end
	end
end

function getModuleSize(handle)
	local e_lfanew = mh.readMemory(handle + 0x3C, "uint32_t[1]")[0]
	local SizeOfImage = mh.readMemory(handle + e_lfanew + 0x50, "uint32_t[1]")[0]
	return SizeOfImage
end

