			local MaximumWidth, MaximumHeight = screenres.right-(screenres.left), screenres.bottom-screenres.top

			local sz = (m_mViewMatrix[3][0] * x + m_mViewMatrix[3][1] * y + m_mViewMatrix[3][2] * z + m_mViewMatrix[3][3])
			local sx = (m_mViewMatrix[0][0] * x + m_mViewMatrix[0][1] * y + m_mViewMatrix[0][2]  * z + m_mViewMatrix[0][3])/2
			local sy = -(m_mViewMatrix[1][0] * x + m_mViewMatrix[1][1] * y + m_mViewMatrix[1][2]  * z + m_mViewMatrix[1][3])/2
			
			local sx = ((MaximumWidth * sx) / sz) + MaximumWidth/2
			local sy = ((MaximumHeight * sy) / sz) + MaximumHeight/2
			
			return sx, sy, sz
		end
		
