				local entity = entitylist[i].entity
				local unkval1 = mh.readMemory(entity + 0x58, "uint32_t[1]")[0]
				local unkval2 = mh.readMemory(unkval1 + 0x4, "char[64]")
				if unkval2[0] ~= 42 and unkval2[0] ~= 115 and mh.readMemory(entity + 0x158, "bool[1]")[0] then
					local pos = mh.readMemory(entity + 0x98, "float[3]")
					local enttype = mh.readMemory(entity + 0x13C, "uint32_t[1]")[0]
					local m_iTeamNum = mh.readMemory(entity + 0xDC, "uint32_t[1]")[0]
					local m_iHealth = mh.readMemory(entity + 0xE4, "uint32_t[1]")[0]
					local x1, y1, z = convert3DCoordsToScreen(pos[0], pos[1], pos[2])
					if m_iTeamNum == 3 then
						if m_iHealth > 0 then
							if z > 0.1 then
								-- print(mh.readMemory(entity + 0x186C, "uint8_t[1]")[0])
								if mh.readMemory(entity + 0x189C, "bool[1]")[0] then
									render:AddText(ImVec2(x1, y1), -1, "player\n"..tostring(m_iHealth))
								else
									-- render:AddText(ImVec2(x1, y1), -1, "bot\n"..tostring(m_iHealth))
									render:AddText(ImVec2(x1, y1), -1, "bot\n"..ffi.string(unkval2):sub(17, -5).."\n"..tostring(m_iHealth))
								end
							end
							imgui.renderDraw3DLine({pos[0], pos[1], pos[2]}, {1280, 720}, -1, 2)
						else
							if z > 0.1 then
								if unkval2[16] == 0x77 then
									render:AddText(ImVec2(x1, y1), 0xFF0000FF, "witch")
								else
									render:AddText(ImVec2(x1, y1), 0xAA9f9f9f, "common")
								end
							end
						end
					elseif z and z > 0.1 and enttype and enttype ~= 7 and mh.readMemory(unkval1, "uint32_t[1]")[0] and mh.readMemory(unkval1, "uint32_t[1]")[0] > 0 then
						if unkval2[24] == 0x77 and unkval2[25] == 0x5F then
							local mdlModel = ffi.string(unkval2)
							if unkval2[28] == 0x5F then -- equipment
								render:AddText(ImVec2(x1, y1), -1, mdlModel:sub(30, -5))
							else -- weapons
								render:AddText(ImVec2(x1, y1), -1, mdlModel:sub(27, -5))
							end
						end
					end
				end
			end
		end
