		ffi.C.ScreenToClient(lj_glfw.glfw.glfwGetWin32Window(window), mousePos)
		
		imgui.lib.ImGui_ImplGlfw_CursorPosCallback(window, mousePos[0], mousePos[1])
		imgui.lib.ImGui_ImplGlfw_MouseButtonCallback(window, 0, (ffi.C.GetKeyState(0x1) > 1) and 1 or 0, 0)
		
	else
		if (lj_glfw.glfw.glfwGetWin32Window(window) ~= ffi.C.GetForegroundWindow()) and (-9999 ~= prevSize[1] or -9999 ~= prevSize[2] or -9999 ~= prevSize[3] or -9999 ~= prevSize[4]) then
			lj_glfw.glfw.glfwSetWindowPos(window, -9999, -9999)
			-- lj_glfw.glfw.glfwSetWindowSize(window, 1, 1)
			-- lj_glfw.glfw.glfwSetWindowAttrib(window, 0x0002000D, 1)
			prevSize = {-9999, -9999, -9999, -9999}
		end
		ffi.C.Sleep(50)
	end

    ig_impl:Render()
    window:swapBuffers()


end

mh.driverUnload()
ig_impl:destroy()
window:destroy()
lj_glfw.terminate()
